api.post("/uploads", async (c) => {
  try {
    const body = await c.req.parseBody();
    const file2 = body["file"];
    if (!file2) return c.json({ success: false, message: "No file provided" }, 400);
    const bucket = c.env.UPLOADS;
    if (!bucket) return c.json({ success: false, message: "Storage not configured" }, 500);
    const key = "uploads/" + Date.now() + "-" + (file2.name || "file");
    await bucket.put(key, file2.stream || file2, { httpMetadata: { contentType: file2.type || "application/octet-stream" } });
    return c.json({ success: true, data: { key, url: "/api/uploads/" + key } });
  } catch (error48) {
    console.error("Upload error:", error48);
    return c.json({ success: false, message: "Upload failed" }, 500);
  }
});
api.get("/uploads/:key{.+}", async (c) => {
  try {
    const bucket = c.env.UPLOADS;
    if (!bucket) return c.json({ success: false, message: "Storage not configured" }, 500);
    const key = c.req.param("key");
    const object2 = await bucket.get(key);
    if (!object2) return c.json({ success: false, message: "File not found" }, 404);
    const headers = new Headers();
    object2.writeHttpMetadata(headers);
    headers.set("etag", object2.httpEtag);
    return new Response(object2.body, { headers });
  } catch (error48) {
    return c.json({ success: false, message: "File retrieval failed" }, 500);
  }
});
