api.get("/surveys", authMiddleware, async (c) => {
  const db = c.env.DB;
  const tenantId = c.get("tenantId");
  const { status, type, search, module: mod, target_type, company_id } = c.req.query();
  let where = "WHERE tenant_id = ?";
  const params = [tenantId];
  if (status && status !== "all") {
    if (status === "active") {
      where += " AND is_active = 1";
    } else if (status === "archived" || status === "inactive") {
      where += " AND is_active = 0";
    }
  }
  if (type) {
    where += " AND visit_type = ?";
    params.push(type);
  }
  if (mod) {
    where += " AND module = ?";
    params.push(mod);
  }
  if (target_type) {
    where += ' AND (target_type = ? OR target_type = "both")';
    params.push(target_type);
  }
  if (company_id) {
    where += " AND (company_id = ? OR company_id IS NULL)";
    params.push(company_id);
  }
  if (search) {
    where += " AND name LIKE ?";
    params.push("%" + search + "%");
  }
  const surveys = await db.prepare("SELECT * FROM questionnaires " + where + " ORDER BY created_at DESC LIMIT 500").bind(...params).all();
  const results = (surveys.results || []).map((q) => {
    try {
      q.questions = JSON.parse(q.questions);
    } catch (e) {
    }
    return { ...q, title: q.name, survey_type: q.visit_type || "adhoc", response_count: 0, completion_rate: 0 };
  });
  return c.json({ success: true, data: results });
});
