            item.line_total -= freeValue;
            subtotal -= freeValue;
            totalDiscount += freeValue;
            appliedPromos.push({ rule_id: rule.id, name: rule.name, type: "BUY_X_GET_Y", free_items: freeItems, discount: freeValue });
